#include "ethernet_w5500.h"
#include <SPI.h>
#include <Ethernet.h>
static byte mac[]={0xDE,0xAD,0xBE,0xEF,0xFE,0xED};
static bool _ok=false;
void ethernet_setup(){Ethernet.init(5);if(Ethernet.begin(mac)==0){Serial.println("[eth] DHCP fail!");if(Ethernet.hardwareStatus()==EthernetNoHardware){Serial.println("[eth] No W5500!");}return;}_ok=true;Serial.printf("[eth] OK IP=%s\n",Ethernet.localIP().toString().c_str());}
bool ethernet_connected(){return _ok&&Ethernet.linkStatus()==LinkON;}
String ethernet_get_ip(){return Ethernet.localIP().toString();}
